const config = $('Workflow Configuration').first().json;
const classification = $input.first().json;
const policy = $input.item.json;

// Decision matrix based on policy rules
const decision = {
  modelSize: policy.preferred_model || 'small',
  allowTools: policy.allow_tools || false,
  retryStrategy: policy.retry_strategy || 'fallback',
  timeoutMs: Math.min(classification.priority === 'critical' ? config.timeoutMs * 0.8 : config.timeoutMs, policy.max_latency_ms || config.timeoutMs),
  maxTokens: policy.max_tokens || config.maxTokens,
  costBudget: Math.min(config.costCeiling, policy.cost_limit || config.costCeiling),
  taskType: classification.taskType,
  confidence: classification.confidence,
  priority: classification.priority
};

// Override to large model for complex reasoning or low confidence
if (classification.taskType === 'reasoning' && classification.confidence < 70) {
  decision.modelSize = 'large';
}

if (classification.priority === 'critical') {
  decision.modelSize = 'large';
}

return decision;

