const metrics = $input.first().json;

// Calculate success rates and performance
const adjustments = [];

for (const metric of metrics) {
  const successRate = metric.successful_executions / metric.total_executions;
  const avgLatency = metric.avg_latency;
  const avgCost = metric.avg_cost;

  let recommendation = metric.model_used;

  // If small model has high success rate and low latency, prefer it
  if (metric.model_used === 'large' && successRate > 0.95 && avgLatency < 5000) {
    recommendation = 'small';
  }

  // If small model has low success rate, upgrade to large
  if (metric.model_used === 'small' && successRate < 0.80) {
    recommendation = 'large';
  }

  adjustments.push({
    task_type: metric.task_type,
    current_model: metric.model_used,
    recommended_model: recommendation,
    success_rate: successRate,
    avg_latency: avgLatency,
    avg_cost: avgCost,
    adjustment_reason: recommendation !== metric.model_used ? 'Performance optimization' : 'No change needed'
  });
}

return adjustments;

